let _menhir_print_token : token -> string =
  fun _tok ->
    match _tok with
    | AMP ->
        "AMP"
    | AMP_AMP ->
        "AMP_AMP"
    | AND ->
        "AND"
    | ARRAY ->
        "ARRAY"
    | ARRAY_CREATE ->
        "ARRAY_CREATE"
    | ARRAY_LENGTH ->
        "ARRAY_LENGTH"
    | ARRAY_MAKE ->
        "ARRAY_MAKE"
    | ASR ->
        "ASR"
    | ASSERT ->
        "ASSERT"
    | AT ->
        "AT"
    | AT_AT ->
        "AT_AT"
    | BANG ->
        "BANG"
    | BOOL_LIT _ ->
        "BOOL_LIT"
    | COL ->
        "COL"
    | COL_EQ ->
        "COL_EQ"
    | COMMA ->
        "COMMA"
    | CREATE ->
        "CREATE"
    | DEFAULT ->
        "DEFAULT"
    | DIV ->
        "DIV"
    | DO ->
        "DO"
    | DOLLARD ->
        "DOLLARD"
    | DONE ->
        "DONE"
    | DOT ->
        "DOT"
    | DOT_LENGTH ->
        "DOT_LENGTH"
